"from youtube_transcript_api import YouTubeTranscriptApi
import urllib.parse as urlparse

def extract_video_id(url):
    """유튜브 URL에서 video id를 추출합니다."""
    parsed_url = urlparse.urlparse(url)
    if parsed_url.hostname == 'youtu.be':
        return parsed_url.path[1:]
    if parsed_url.hostname in ('www.youtube.com', 'youtube.com'):
        if parsed_url.path == '/watch':
            p = urlparse.parse_qs(parsed_url.query)
            return p.get('v', [None])[0]
        if parsed_url.path.startswith('/embed/'):
            return parsed_url.path.split('/')[2]
        if parsed_url.path.startswith('/v/'):
            return parsed_url.path.split('/')[2]
    return None

def get_transcript(video_url):
    """유튜브 영상의 자막을 텍스트로 추출합니다."""
    video_id = extract_video_id(video_url)
    if not video_id:
        raise ValueError("유효하지 않은 유튜브 URL입니다.")

    try:
        # 한국어('ko')를 최우선으로, 없으면 자동번역된 한국어나 영어 가져오기
        transcript_list = YouTubeTranscriptApi.list_transcripts(video_id)

        try:
            transcript = transcript_list.find_transcript(['ko'])
        except:
            # 한국어가 없으면 영어를 가져와서 번역 (youtube-transcript-api 자동 번역 기능)
            transcript = transcript_list.find_transcript(['en']).translate('ko')

        transcript_data = transcript.fetch()

        full_text = " ".join([t['text'] for t in transcript_data])
        return full_text

    except Exception as e:
        print(f"자막 추출 실패: {e}")
        return None

if __name__ == "__main__":
    # 테스트용
    url = "https://youtu.be/FC9dB065lL8?si=0wdMpSMS5yKFfXtV"
    text = get_transcript(url)
    print(text[:500] if text else "실패")
"
